"use client";

import { useState, useEffect } from "react";
import { SemanticSection } from "@/components/landing/SemanticSection";
import { ParallaxBackground } from "@/components/landing/ParallaxBackground";
import { TypewriterText } from "@/components/landing/TypewriterText";
import { useIntelligence } from "@/context/IntelligenceContext";

import { useRouter } from "next/navigation";

export default function LandingPage() {
  const { isBooted, setDoorState } = useIntelligence();
  const [entryLocked, setEntryLocked] = useState(true);
  const [showHeroSub, setShowHeroSub] = useState(false);
  const [sessionId, setSessionId] = useState("");
  const router = useRouter();

  const handleEnterSystem = () => {
     // Close the doors (visible black overlay)
     setDoorState("closed");
     
     // Wait for 900ms transition, then route
     setTimeout(() => {
        router.push("/overview");
        
        // After route, open valid doors
        // Note: The BlastDoorTransition component inside RootLayout will persist.
        // But we need to set state to "open" AFTER the new page mounts or slightly after route.
        // If we set it here, it might happen too early if route takes time.
        // Actually, BlastDoorTransition listens to doorState.
        // If we stay "closed", the user sees black.
        // We want to open it *on the next page*.
        // So we leave it "closed" here.
        // The *Dashboard Layout* or *Overview Page* should set it to "open" on mount.
        // Or we set a timeout here if we assume fast routing.
        // Better: Set it to "closed", then router.push. 
        // The RootLayout persists.
        // In Dashboard Layout, we can useEffect(() => setDoorState("open"), []).
     }, 900);
  };

  // Micro Task 29.7: Entry Lock Animation
  useEffect(() => {
    if (isBooted) {
      // Sequence: Screen Black -> ARGUS fade in (handled by layout boot? No, this is specific landing entry)
      // Actually BootSequence handles the initial "System Boot". 
      // User requested "Entire screen black, ARGUS appears center".
      // We will treat "BootSequence" as the BIOS load, and this as the "OS Login".
      
      const unlockTimer = setTimeout(() => {
        setEntryLocked(false);
      }, 2500); // Lock for 2.5s total (including text reveals)

      const subTimer = setTimeout(() => {
        setShowHeroSub(true);
      }, 1200);

      return () => {
        clearTimeout(unlockTimer);
        clearTimeout(subTimer);
      };
    }
  }, [isBooted]);

  // Generate Session ID on client side only to prevent hydration mismatch
  useEffect(() => {
    setSessionId(Math.random().toString(36).substr(2, 9).toUpperCase());
  }, []);

  return (
    <main className={`relative w-full text-text-primary selection:bg-accent selection:text-white ${entryLocked ? "h-screen overflow-hidden" : "min-h-[400vh]"}`}>
      
      {/* 29.2 Parallax Background (Global) */}
      <ParallaxBackground />

      {/* 29.7 Entry Lock Overlay (The "Black Screen" phase) */}
      {/* If entryLocked is true, we might want a dedicated overlay or just let the Hero handle it if it's full screen high z-index */}
      {/* The user said "Entire screen black". BootSequence does this too. */}
      {/* We will let the Hero Section BE the lock screen initially. */}

      {/* PHASE 1: HERO (ARGUS ARRIVAL) */}
      <SemanticSection phase="hero" className="z-20 h-screen" allowMotion={isBooted}>
        <div className="relative z-10 text-center">
          <h1 className="font-space font-bold text-8xl md:text-[10rem] tracking-tighter leading-none text-white mix-blend-difference mb-6">
            ARGUS
          </h1>
          <div className={`transition-opacity duration-1000 ${showHeroSub ? "opacity-100" : "opacity-0"}`}>
             <p className="font-mono text-sm tracking-[0.4em] text-accent/80 uppercase">
               Defense Intelligence Network
             </p>
          </div>
        </div>
        
        {/* Scroll Hint */}
        <div className={`absolute bottom-12 transition-all duration-1000 delay-1000 ${!entryLocked ? "opacity-30 translate-y-0" : "opacity-0 translate-y-4"}`}>
           <div className="w-[1px] h-16 bg-gradient-to-b from-white to-transparent mx-auto"></div>
        </div>
      </SemanticSection>


      {/* PHASE 2: REALIZATION (BRIEFING LAYERS) */}
      {/* 01 DETECT */}
      <SemanticSection phase="detect" className="z-20 border-l-[2px] border-accent/30 pl-8 ml-4 md:ml-24 max-w-4xl py-24 my-12">
        <div className="font-mono text-xs text-accent tracking-widest mb-4">01 // DETECT</div>
        <h2 className="font-space text-5xl md:text-7xl font-light mb-6 leading-tight">
          Weak Signals <br/>
          <span className="text-white/40">Before They Surface.</span>
        </h2>
        <p className="font-sans text-lg text-text-secondary max-w-xl leading-relaxed">
          The system scans millions of unstructured data points???patents, whitepapers, dark web chatter???identifying TRL 1-3 technologies invisible to standard surveillance.
        </p>
      </SemanticSection>

      {/* 02 ANALYZE */}
      <SemanticSection phase="analyze" className="z-20 border-l-[2px] border-accent/30 pl-8 ml-4 md:ml-24 max-w-4xl py-24 my-12">
        <div className="font-mono text-xs text-accent tracking-widest mb-4">02 // ANALYZE</div>
        <h2 className="font-space text-5xl md:text-7xl font-light mb-6 leading-tight">
          Pattern <br/>
          <span className="text-white/40">Recognition.</span>
        </h2>
        <p className="font-sans text-lg text-text-secondary max-w-xl leading-relaxed">
          Automated TRL assessment and citation graph analysis. ARGUS distinguishes between theoretical hype and viable engineering capability.
        </p>
      </SemanticSection>

      {/* 03 PREDICT */}
      <SemanticSection phase="predict" className="z-20 border-l-[2px] border-accent/30 pl-8 ml-4 md:ml-24 max-w-4xl py-24 my-12">
        <div className="font-mono text-xs text-accent tracking-widest mb-4">03 // PREDICT</div>
        <h2 className="font-space text-5xl md:text-7xl font-light mb-6 leading-tight">
          Strategic <br/>
          <span className="text-white/40">Convergence.</span>
        </h2>
        <p className="font-sans text-lg text-text-secondary max-w-xl leading-relaxed">
          Modeling the intersection of disparate timelines. When AI meets Quantum. When Bio meets Cyber. We predict the flashpoint.
        </p>
      </SemanticSection>


      {/* PHASE 3: MAP (Living Intelligence) */}
      <SemanticSection phase="map" className="z-20 h-screen bg-gradient-to-b from-transparent to-background-secondary/80 backdrop-blur-sm">
        <div className="text-center max-w-5xl mx-auto px-6">
           <div className="inline-block border border-white/10 px-4 py-1 rounded-full bg-white/5 backdrop-blur-md mb-8">
             <span className="font-mono text-[10px] text-accent tracking-widest">LIVE SYSTEM FEED</span>
           </div>
           
           <h2 className="font-space text-4xl md:text-6xl mb-12">
             The Living Map
           </h2>

           {/* Semantic Grid / Map Graphic Placeholder */}
           <div className="w-full h-[400px] border border-white/5 rounded-lg bg-black/40 relative overflow-hidden group">
              <div className="absolute inset-0 bg-[url('/grid.svg')] opacity-20"></div>
              {/* Animated Nodes */}
              <div className="absolute top-1/2 left-1/4 w-2 h-2 bg-accent rounded-full animate-pulse shadow-[0_0_15px_rgba(34,211,238,0.5)]"></div>
              <div className="absolute top-1/3 right-1/4 w-2 h-2 bg-signal rounded-full animate-pulse delay-500 shadow-[0_0_15px_rgba(245,158,11,0.5)]"></div>
              
              <div className="absolute bottom-10 left-10 font-mono text-xs text-text-muted">
                <div className="mb-2">NODES: 14,205</div>
                <div>EDGES: 82,101</div>
              </div>
           </div>
        </div>
      </SemanticSection>


      {/* PHASE 4: THRESHOLD (Typewriter Entry) */}
      <SemanticSection phase="threshold" className="z-20 h-screen flex flex-col justify-center items-center bg-black/60 backdrop-blur-xl">
        <div className="text-center">
          <p className="font-mono text-xs text-white/30 tracking-[0.2em] mb-4">
            SECURE CONNECTION ESTABLISHED
          </p>
          
          {/* Micro Task 29.5: Typewriter Animation */}
          <h2 className="font-mono text-xl md:text-2xl text-accent mb-12 tracking-widest">
            <TypewriterText text="AUTHORIZED PERSONNEL ONLY" delay={500} />
          </h2>

          <div 
             onClick={handleEnterSystem}
             className="group relative inline-flex items-center justify-center px-16 py-6 overflow-hidden font-mono text-sm tracking-widest text-white border border-white/10 transition-all duration-500 hover:border-accent hover:bg-accent/5 cursor-pointer"
          >
            <span className="absolute inset-0 w-full h-full bg-gradient-to-r from-transparent via-white/5 to-transparent -translate-x-full group-hover:animate-shimmer"></span>
            <span className="relative">ENTER SYSTEM</span>
          </div>
          
          <div className="mt-12 text-[10px] text-white/20 font-mono">
            ID: {sessionId} // SESSION: ACTIVE
          </div>
        </div>
      </SemanticSection>

    </main>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { getRadarTechnologies } from "@/services/radarService";
import { getGraphNodes } from "@/services/graphService";
import type { RadarTechnology } from "@/types/radar";
import { RING_CONFIG } from "@/types/radar";

import { useIntelligence } from "@/context/IntelligenceContext";

export function TechnologyRadar({ className, svgClassName }: { className?: string, svgClassName?: string }) {
  const technologies = getRadarTechnologies();
  const graphNodes = getGraphNodes();
  const router = useRouter();
  const { setFocusedNodeId, focusedNodeId } = useIntelligence(); 
  const [hoveredId, setHoveredId] = useState<string | null>(null);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const cx = 160;
  const cy = 160;

  const getDisplayTech = (): RadarTechnology | null => {
    if (selectedId) return technologies.find((t) => t.id === selectedId) || null;
    if (hoveredId) return technologies.find((t) => t.id === hoveredId) || null;
    return null;
  };

  const displayTech = getDisplayTech();

  // Map radar tech to graph node by label match for navigation
  const findGraphNodeId = (tech: RadarTechnology): string | null => {
    const match = graphNodes.find(n => 
      n.type === "technology" && 
      (n.label.toLowerCase().includes(tech.label.toLowerCase().split(" ")[0]) ||
       tech.label.toLowerCase().includes(n.label.toLowerCase().split(" ")[0]))
    );
    return match?.id || null;
  };

  const handleDotClick = (tech: RadarTechnology) => {
    const newId = selectedId === tech.id ? null : tech.id;
    setSelectedId(newId);
    setFocusedNodeId(newId); // Trigger Spatial Zoom
  };

  const handleDotDoubleClick = (tech: RadarTechnology) => {
    const nodeId = findGraphNodeId(tech);
    if (nodeId) {
      router.push(`/trl?tech=${nodeId}`);
    }
  };

  return (
    <div className={`flex flex-col gap-4 ${className || ''}`}>
      <div className="flex items-start gap-8">
        {/* Radar SVG */}
        <div className="relative">
          <svg
            viewBox="0 0 320 320"
            className={svgClassName || "w-80 h-80"}
            fill="none"
            onClick={(e) => {
              if (e.target === e.currentTarget) {
                 setSelectedId(null);
                 setFocusedNodeId(null);
              }
            }}
          >
            {/* Grid rings */}
            <circle
              cx={cx}
              cy={cy}
              r={RING_CONFIG[3].radius}
              className="stroke-border"
              strokeWidth="1"
              strokeDasharray="4 4"
            />
            <circle
              cx={cx}
              cy={cy}
              r={RING_CONFIG[2].radius}
              className="stroke-border"
              strokeWidth="1"
              strokeDasharray="4 4"
            />
            <circle
              cx={cx}
              cy={cy}
              r={RING_CONFIG[1].radius}
              className="stroke-border"
              strokeWidth="1"
              strokeDasharray="4 4"
            />

            {/* Center point */}
            <circle cx={cx} cy={cy} r={4} className="fill-accent" />

            {/* Crosshairs */}
            <line
              x1={cx - 145}
              y1={cy}
              x2={cx + 145}
              y2={cy}
              className="stroke-border/50"
              strokeWidth="1"
            />
            <line
              x1={cx}
              y1={cy - 145}
              x2={cx}
              y2={cy + 145}
              className="stroke-border/50"
              strokeWidth="1"
            />

            {/* Technology dots */}
            {technologies.map((tech) => {
              const radius = RING_CONFIG[tech.ring].radius;
              const angleRad = (tech.angle * Math.PI) / 180;
              const x = cx + radius * Math.cos(angleRad);
              const y = cy + radius * Math.sin(angleRad);
              const isHovered = hoveredId === tech.id;
              const isSelected = selectedId === tech.id;
              const isActive = isHovered || isSelected;
              const baseOpacity = tech.ring === 1 ? 1 : tech.ring === 2 ? 0.7 : 0.4;

              return (
                <g
                  key={tech.id}
                  className="cursor-pointer"
                  onMouseEnter={() => setHoveredId(tech.id)}
                  onMouseLeave={() => setHoveredId(null)}
                  onClick={() => handleDotClick(tech)}
                  onDoubleClick={() => handleDotDoubleClick(tech)}
                >
                  {isSelected && (
                    <circle
                      cx={x}
                      cy={y}
                      r={18}
                      className="fill-none stroke-accent"
                      strokeWidth="2"
                      strokeDasharray="4 2"
                    />
                  )}
                  <circle
                    cx={x}
                    cy={y}
                    r={14}
                    className="fill-accent/20"
                    style={{
                      opacity: isActive ? 1 : 0,
                      transition: "opacity 150ms ease-out",
                    }}
                  />
                  <circle
                    cx={x}
                    cy={y}
                    r={isActive ? 8 : 6}
                    className="fill-accent"
                    style={{
                      opacity: isActive ? 1 : baseOpacity,
                      transition: "all 150ms ease-out",
                    }}
                  />
                </g>
              );
            })}
          </svg>

          {displayTech && (
            <div
              className="tooltip tooltip-visible"
              style={{
                left: "50%",
                bottom: "calc(100% + 8px)",
                transform: "translateX(-50%)",
                minWidth: "180px",
              }}
            >
              <div className="font-medium text-text-primary">{displayTech.label}</div>
              <div className="text-text-muted">{RING_CONFIG[displayTech.ring].label} to maturity</div>
              {displayTech.description && (
                <div className="text-text-secondary mt-1 text-[11px]">
                  {displayTech.description}
                </div>
              )}
              {selectedId === displayTech.id && (
                <div className="text-accent mt-1 text-[10px]">Double-click ??? TRL Assessment</div>
              )}
            </div>
          )}
        </div>

        {/* Legend */}
        <div className="flex flex-col gap-3 pt-4">
          <h3 className="text-label text-text-primary uppercase tracking-wider">
            Time to Maturity
          </h3>
          <div className="flex flex-col gap-2">
            <div className="flex items-center gap-2">
              <span className="w-3 h-3 rounded-full bg-accent" />
              <span className="text-caption text-text-secondary">{RING_CONFIG[1].label}</span>
            </div>
            <div className="flex items-center gap-2">
              <span className="w-3 h-3 rounded-full bg-accent/60" />
              <span className="text-caption text-text-secondary">{RING_CONFIG[2].label}</span>
            </div>
            <div className="flex items-center gap-2">
              <span className="w-3 h-3 rounded-full bg-accent/30" />
              <span className="text-caption text-text-secondary">{RING_CONFIG[3].label}</span>
            </div>
          </div>
          <div className="mt-4 pt-4 border-t border-border">
            <p className="text-caption text-text-muted">
              Click to select ??? Double-click ??? TRL
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";

interface TypewriterTextProps {
  text: string;
  delay?: number;
  className?: string;
}

export function TypewriterText({ text, delay = 0, className = "" }: TypewriterTextProps) {
  const [displayedText, setDisplayedText] = useState("");
  const [showCursor, setShowCursor] = useState(false);
  const [isTypingComplete, setIsTypingComplete] = useState(false);

  useEffect(() => {
    let timeout: NodeJS.Timeout;
    let interval: NodeJS.Timeout;

    // Start typing after delay
    timeout = setTimeout(() => {
      setShowCursor(true);
      
      let currentIndex = 0;
      interval = setInterval(() => {
        if (currentIndex <= text.length) {
          setDisplayedText(text.slice(0, currentIndex));
          currentIndex++;
        } else {
          clearInterval(interval);
          setIsTypingComplete(true);
        }
      }, 40); // 40ms per char
      
    }, delay);

    return () => {
      clearTimeout(timeout);
      clearInterval(interval);
    };
  }, [text, delay]);

  // Cursor logic: Blink when finished, then fade out
  useEffect(() => {
    if (isTypingComplete) {
      const timeout = setTimeout(() => {
        setShowCursor(false);
      }, 1200); // Blink for 1.2s then fade
      return () => clearTimeout(timeout);
    }
  }, [isTypingComplete]);

  return (
    <span className={`font-mono ${className}`}>
      {displayedText}
      <span className={`inline-block w-2.5 h-[1.2em] bg-accent ml-1 align-bottom ${showCursor ? "animate-pulse" : "opacity-0 transition-opacity duration-300"}`}></span>
    </span>
  );
}

"use client";

import { useIntelligence } from "@/context/IntelligenceContext";
import { useEffect, useState } from "react";

export function ArgusVoiceLayer() {
  const { activePhase } = useIntelligence();
  const [voiceText, setVoiceText] = useState("");
  const [isVisible, setIsVisible] = useState(false);

  // Mapping phases to system lines
  const voiceLines: Record<string, string> = {
    hero: "System initializing...",
    intro: "System initializing...",
    detect: "Monitoring signal emergence.",
    analyze: "Cross-referencing maturity indicators.",
    predict: "Modeling convergence windows.",
    map: "Live telemetry active.",
    threshold: "Authorization required.",
  };

  useEffect(() => {
    const text = voiceLines[activePhase];
    if (text) {
      // Fade Out old
      setIsVisible(false);
      
      // Wait for fade out, then set new text and Fade In
      const timeout = setTimeout(() => {
        setVoiceText(text);
        setIsVisible(true);
      }, 600); // Match transition duration

      // Hold for 3s then fade out
      const holdTimeout = setTimeout(() => {
        setIsVisible(false);
      }, 3600); // 600ms in + 3000ms hold

      return () => {
        clearTimeout(timeout);
        clearTimeout(holdTimeout);
      };
    }
  }, [activePhase]);

  return (
    <div className="fixed bottom-8 left-8 z-40 pointer-events-none">
       <div 
         className={`font-mono text-xs text-accent/70 transition-all duration-600 ease-out ${
           isVisible ? "opacity-100 tracking-widest translate-y-0" : "opacity-0 tracking-normal translate-y-2"
         }`}
       >
         <div className="mr-2 text-accent/50 animate-pulse inline-block">???</div>
          {"> "}{voiceText}
       </div>
    </div>
  );
}

"use client";

import { useIntelligence } from "@/context/IntelligenceContext";
import { useEffect, useState } from "react";
import { usePathname } from "next/navigation";

export function BlastDoorTransition() {
  const { doorState, setDoorState } = useIntelligence();
  const pathname = usePathname();

  // If we are on Landing Page (/), doors should be "Open" (invisible) or strictly speaking "Not There".
  // But wait, the TRANSITION happens when we LEAVE Landing.
  // We want the doors to ClOSE (appear) when we click "Initiate".
  // Then we route.
  // Then on Dashboard, they OPEN.
  
  // Implementation:
  // We use fixed overlays. 
  // State "closed": Panels cover screen.
  // State "open": Panels slide out.
  // State "opening": transitioning.

  // Logic: 
  // Initial state on App Load: "Open" (invisible)? 
  // The Landing Page IS the content.
  
  // When doorState === "closed", visual is BLACK SCREEN.
  // When doorState === "opening", panels slide out.
  // When doorState === "open", panels are gone (pointer-events-none).

  return (
    <div className={`fixed inset-0 z-[100] pointer-events-none flex`}>
      {/* Left Panel */}
      <div 
        className={`h-full w-1/2 bg-background-primary transition-transform duration-[900ms] ease-[cubic-bezier(0.6,0,0.2,1)] will-change-transform ${
          doorState === "closed" ? "translate-x-0" : "-translate-x-full"
        }`}
      ></div>

      {/* Right Panel */}
       <div 
        className={`h-full w-1/2 bg-background-primary transition-transform duration-[900ms] ease-[cubic-bezier(0.6,0,0.2,1)] will-change-transform ${
          doorState === "closed" ? "translate-x-0" : "translate-x-full"
        }`}
      ></div>
    </div>
  );
}

"use client";

import { useIntelligence } from "@/context/IntelligenceContext";
import { SituationRegion } from "@/components/spatial/SituationRegion";
import { ArgusDepthLayer } from "@/components/spatial/ArgusDepthLayer";
import { useEffect } from "react";

export function ArgusEnvironment() {
  const { activeRegion, focusedNodeId, setFocusedNodeId } = useIntelligence();

  // Task 34: Handle ESC Loop
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === "Escape" && focusedNodeId) {
        setFocusedNodeId(null);
      }
    };
    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [focusedNodeId, setFocusedNodeId]);

  // 3D Transform Logic
  // We move the "Stage" opposite to the desired view.
  // We also apply a slight rotation for visual flair (max 3deg).
  
  const getCameraTransform = () => {
    let baseTransform = "";
    
    // Zoom focus (Task 34)
    if (focusedNodeId) {
       return "scale(1.05) translateZ(50px)";
    }

    switch (activeRegion) {
      case "corpus": 
        // Move World Right (so Corpus comes from Left) + Slight Tilt
        baseTransform = "translateX(50vw) rotateY(2deg)"; 
        break;
      case "trajectory": 
        // Move World Left + Slight Tilt
        baseTransform = "translateX(-50vw) rotateY(-2deg)"; 
        break;
      case "signals": 
        baseTransform = "translateY(50vh) rotateX(-2deg)";
        break;
      case "maturity": 
        baseTransform = "translateY(-50vh) rotateX(2deg)";
        break;
      case "situation":
      default:
         baseTransform = "translate3d(0,0,0) rotateY(0deg)";
         break;
    }
    return baseTransform;
  };

  // Regions stay in their absolute positions, but the CONTAINER moves.
  // Note: Previous I did `translate(100vw, 0)` for the container.
  // Now I want `translateX` to physically move the track.
  
  const getStageTransform = () => {
     // If Active is Corpus (-100vw), we translate container (+100vw) to bring it to 0.
     if (focusedNodeId) return "scale(1.05)";

     switch (activeRegion) {
        case "corpus": return "translateX(100vw)";
        case "trajectory": return "translateX(-100vw)";
        case "signals": return "translateY(100vh)";
        case "maturity": return "translateY(-100vh)";
        default: return "translate3d(0,0,0)";
     }
  };

  return (
    <div 
      className="relative w-screen h-screen overflow-hidden bg-background-primary"
      style={{ perspective: "1200px" }} // Perspective Container
    >
       <div 
          className="absolute inset-0 w-full h-full transition-transform duration-1000 ease-[cubic-bezier(0.2,0,0.2,1)] will-change-transform transform-style-3d"
          style={{ 
             transform: getStageTransform(),
             transformStyle: "preserve-3d"
          }}
       >
          {/* --- DEPTH LAYERS (Parallax Backgrounds) --- */}
          
          {/* BACK LAYER: Starfield / Deep Grid */}
          <ArgusDepthLayer depth="back" className="opacity-40">
              <div className="w-[200vw] h-[200vh] -translate-x-1/2 -translate-y-1/2 absolute left-1/2 top-1/2 bg-[url('/grid.png')] bg-repeat opacity-20"></div>
              {/* Optional: Add slow drifting particles here */}
          </ArgusDepthLayer>

          {/* MID LAYER: Secondary UI Elements / Connecting Lines */}
          <ArgusDepthLayer depth="mid" className="pointer-events-none">
             {/* Floating decorative elements that sit behind the main content but in front of deep bg */}
             <div className="absolute top-1/4 left-1/4 w-64 h-64 border border-accent/5 rounded-full animate-pulse-slow"></div>
             <div className="absolute bottom-1/4 right-1/4 w-96 h-96 border border-white/5 rounded-full"></div>
          </ArgusDepthLayer>

          {/* FRONT LAYER: Active Regions (The Content) */}
          <div 
             className="absolute inset-0 w-full h-full"
             style={{ transform: "translateZ(0)", transformStyle: "preserve-3d" }}
          >
              {/* CENTER: Situation */}
              <div className="absolute inset-0 w-full h-full pointer-events-auto">
                 <SituationRegion />
              </div>

              {/* LEFT: Corpus */}
              <div className="absolute inset-0 w-full h-full -translate-x-full border-r border-white/5 bg-background-secondary/90 backdrop-blur-sm pointer-events-auto">
                 <div className="flex flex-col items-center justify-center h-full">
                    <h1 className="text-heading-1 text-white/50 font-mono mb-4">CORPUS INTEGRITY</h1>
                    <div className="w-96 h-2 bg-white/10 overflow-hidden"><div className="h-full bg-accent w-2/3 animate-shimmer"></div></div>
                 </div>
              </div>

              {/* RIGHT: Trajectory */}
              <div className="absolute inset-0 w-full h-full translate-x-full border-l border-white/5 bg-background-secondary/90 backdrop-blur-sm pointer-events-auto">
                 <div className="flex flex-col items-center justify-center h-full">
                    <h1 className="text-heading-1 text-white/50 font-mono">TRAJECTORY SIMULATION</h1>
                 </div>
              </div>

              {/* TOP: Signals */}
              <div className="absolute inset-0 w-full h-full -translate-y-full border-b border-white/5 bg-background-secondary/90 backdrop-blur-sm pointer-events-auto">
                 <div className="flex flex-col items-center justify-center h-full">
                    <h1 className="text-heading-1 text-white/50 font-mono">SIGNAL INTERCEPT</h1>
                 </div>
              </div>

              {/* BOTTOM: Maturity */}
              <div className="absolute inset-0 w-full h-full translate-y-full border-t border-white/5 bg-background-secondary/90 backdrop-blur-sm pointer-events-auto">
                 <div className="flex flex-col items-center justify-center h-full">
                    <h1 className="text-heading-1 text-white/50 font-mono">MATURITY INDEX</h1>
                 </div>
              </div>
          </div>
       </div>

       {/* Overlay Dimmer for Focus Mode */}
       <div 
          className={`absolute inset-0 bg-black/60 backdrop-blur-sm transition-opacity duration-500 pointer-events-auto cursor-zoom-out ${focusedNodeId ? "opacity-100" : "opacity-0 pointer-events-none"}`}
          style={{ zIndex: 40 }}
          onClick={() => setFocusedNodeId(null)}
       />
    </div>
  );
}

"use client";

import React, { createContext, useContext, useState, useEffect } from "react";

export type UserRole = "analyst" | "commander";

export interface AuditLog {
  id: string;
  timestamp: string;
  action: string;
  component: string;
  details: string;
  source: "deterministic" | "ai" | "system" | "user";
  role?: UserRole | "system";
}

interface IntelligenceContextType {
  activeRole: UserRole;
  setActiveRole: (role: UserRole) => void;
  secureMode: boolean;
  setSecureMode: (mode: boolean) => void;
  isBooted: boolean;
  setBooted: (booted: boolean) => void;
  
  // Task 30: Voice & Door State
  activePhase: string;
  setPhase: (phase: string) => void;
  doorState: "closed" | "opening" | "open";
  setDoorState: (state: "closed" | "opening" | "open") => void;

  // Task 31/37: Spatial Navigation
  activeRegion: "situation" | "corpus" | "maturity" | "trajectory" | "signals";
  setActiveRegion: (region: "situation" | "corpus" | "maturity" | "trajectory" | "signals") => void;

  // Task 34: Node Focus (Spatial Zoom)
  focusedNodeId: string | null;
  setFocusedNodeId: (id: string | null) => void;

  logs: AuditLog[];
  addLog: (log: Omit<AuditLog, "id" | "timestamp">) => void;
}

const IntelligenceContext = createContext<IntelligenceContextType | undefined>(undefined);

export function IntelligenceProvider({ children }: { children: React.ReactNode }) {
  const [secureMode, setSecureMode] = useState(true);
  const [userRole, setUserRoleState] = useState<UserRole>("analyst");
  const [logs, setLogs] = useState<AuditLog[]>([]);
  const [isBooted, setIsBooted] = useState(false);
  
  // Task 30 State
  const [activePhase, setActivePhase] = useState("hero");
  const [doorState, setDoorState] = useState<"closed" | "opening" | "open">("open");

  // Task 31/37 State
  const [activeRegion, setActiveRegion] = useState<"situation" | "corpus" | "maturity" | "trajectory" | "signals">("situation");
  const [focusedNodeId, setFocusedNodeId] = useState<string | null>(null);

  const setUserRole = (role: UserRole) => {
    setUserRoleState(role);
    if (role === "analyst" && !secureMode) {
      setSecureMode(true);
      addLog({
        action: "MODE_ENFORCE",
        component: "System",
        details: "Secure Mode enforced by role change to ANALYST",
        source: "system",
        role: "system", 
      });
    }

    addLog({
      action: "ROLE_CHANGE",
      component: "AuthSystem",
      details: `User role switched to ${role.toUpperCase()}`,
      source: "user",
      role: role,
    });
  };

  // setSecureMode wrapper not needed as we expose strict setter, 
  // but let's keep the logging logic if we want to expose a toggle.
  // The original code had toggleSecureMode but didn't expose it in the interface?
  // It exposed setSecureMode directly.
  // The original code exposed { secureMode, setSecureMode, ... }
  // I will just use setSecureMode directly to match interface.

  const addLog = (log: Omit<AuditLog, "id" | "timestamp">) => {
    const newLog: AuditLog = {
      ...log,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: new Date().toISOString(),
      role: log.role || userRole,
    };
    setLogs((prev) => [newLog, ...prev].slice(0, 50));
  };

  useEffect(() => {
    addLog({
      action: "SYSTEM_INIT",
      component: "System",
      details: "ACTIF Intelligence System Initialized",
      source: "system",
      role: "system",
    });
  }, []);

  return (
    <IntelligenceContext.Provider 
      value={{ 
        secureMode, 
        setSecureMode,
        activeRole: userRole, 
        setActiveRole: setUserRole,
        isBooted,
        setBooted: setIsBooted,
        activePhase,
        setPhase: setActivePhase,
        doorState,
        setDoorState,
        activeRegion,
        setActiveRegion,
        focusedNodeId,
        setFocusedNodeId, 
        logs, 
        addLog 
      }}
    >
      {children}
    </IntelligenceContext.Provider>
  );
}

export function useIntelligence() {
  const context = useContext(IntelligenceContext);
  if (context === undefined) {
    throw new Error("useIntelligence must be used within an IntelligenceProvider");
  }
  return context;
}
